INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 2, 5118061, 1, 20063115, 2834, 10118, 91002, "ペコリーヌとの出会い", "青空の下で謁見", 40, "フリーマーケット会場", 7);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 2, 5118062, 1, 20063115, 2835, 10118, 91002, "マホとの出会い", "未来の騎空団\nマスコット？", 40, "フリーマーケット会場", 7);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 2, 5118063, 1, 20063115, 2837, 10118, 91002, "アキノとの出会い", "お嬢さまからの\n緊急依頼", 40, "ランドソル市街地", 7);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 2, 5118064, 1, 20063115, 4108402, 10118, 91002, "ジュンとの出会い", "黄金色の悩みごと", 40, "フリーマーケット会場", 18);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 2, 5118065, 1, 20063115, 4107402, 10118, 91002, "カオリとの出会い", "白熱！　格闘大会！", 40, "フリーマーケット会場", 18);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 1, "太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 2, 5118066, 1, 20063115, 9000227, 10118, 91002, "ニノンとの出会い", "祭り太鼓はオーエドの華", 40, "オーエド町", 16);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 3, 5118067, 1, 20063115, 2101181, 10118, 91002, "スズナとの出会い", "人気者は遅れて\nやってくる", 40, "フリーマーケット会場", 19);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 3, 5118068, 1, 20063115, 4109402, 10118, 91002, "ナナカとの出会い", "巫女・ミーツ・魔法少女", 40, "ランドソル市街地", 18);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 3, 5118069, 1, 20063115, 4305402, 10118, 91002, "キャル＆コッコロとの出会い", "ネズ耳は二度なくなる", 40, "フリーマーケット会場", 18);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 3, 5118070, 1, 20063115, 4101402, 10118, 91002, "ユカリとの出会い", "この出会いにカンパイ！", 40, "ランドソル市街地", 18);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 0, "ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 3, 5118071, 1, 20063115, 4106402, 10118, 91002, "アオイとの出会い", "陰陽アンサンブル", 40, "ランドソル市街地", 18);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (8, 1, "ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 3, 5118072, 1, 20063115, 2836, 10118, 91002, "シノブとの出会い", "運試し十番勝負！", 40, "フリーマーケット会場", 7);
INSERT INTO `v1_03a41938f494afecb4d6f187b3e6ff7c748e9a9d8aca3332c57866a2d98e0ba0` VALUES (0, 0, 0, 1, 5118600, 0, 20063115, 0, 10118, 0, "オープニング", "彼女たちの新たな日常", 0, 0, 0);
